data.query:
mutation MetaobjectCreate($metaobject: MetaobjectCreateInput!) {
    metaobjectCreate(metaobject: $metaobject) {
        metaobject {
            id
            type
            handle
            displayName
            fields {
                key
                value
                type
            }
        }
        userErrors {
            field
            message
            code
        }
    }
}
